import React, { useState, useRef, useEffect } from 'react';
import '../styles/PhoneIntel.css';
import { COUNTRY_CODES } from './CountryCodePicker';
import { api } from '../utils/api';
import { THEMES } from '../themes';

/**
 * Phone Intelligence Component
 * 
 * Features:
 * - Phone number normalization and validation
 * - Automatic country detection from phone prefix
 * - Optional country selection with searchable dropdown
 * - Scan modes: Light (fast) and Deep (comprehensive OSINT)
 * - Professional OSINT findings display
 * - Real-time progress tracking
 */
const PhoneIntel = ({ theme }) => {
  const t = THEMES[theme || 'dark'];

  // Phone input state
  const [phoneInput, setPhoneInput] = useState('');
  const [selectedCountry, setSelectedCountry] = useState('');
  const [countrySearch, setCountrySearch] = useState('');
  const [showCountryDropdown, setShowCountryDropdown] = useState(false);
  const [detectedCountry, setDetectedCountry] = useState(null);

  // Scan state
  const [scanMode, setScanMode] = useState('light');
  const [isLoading, setIsLoading] = useState(false);
  const [progress, setProgress] = useState(0);

  // Results state
  const [lookupResult, setLookupResult] = useState(null);
  const [error, setError] = useState(null);

  // Refs for dropdown handling
  const countryDropdownRef = useRef(null);


  /**
   * Normalize phone number to standard format: +<countrycode><localnumber>
   * Removes spaces, dashes, parentheses, etc.
   */
  const normalizePhoneNumber = (phone, countryObj = null) => {
    if (!phone) return '';

    // Remove all non-numeric characters except leading +
    let cleaned = phone.replace(/[^\d+]/g, '');

    // If it starts with +, it should be international format
    if (cleaned.startsWith('+')) {
      return cleaned;
    }

    // If we have a selected country, prepend its dial code
    if (countryObj?.dial) {
      const dialCode = countryObj.dial.replace(/\D/g, ''); // Extract just digits
      const localDigits = cleaned.replace(/^0+/, ''); // Remove leading zeros
      return `+${dialCode}${localDigits}`;
    }

    // If no country selected but starts with international prefix format, return as-is
    if (cleaned.length > 5) {
      return `+${cleaned}`;
    }

    return '';
  };

  /**
   * Detect country from phone number prefix
   * E.g., +233 → Ghana, +234 → Nigeria, +1 → US/Canada
   */
  const detectCountryFromPhone = (normalizedPhone) => {
    if (!normalizedPhone || !normalizedPhone.startsWith('+')) {
      return null;
    }

    // Extract the dial code (everything after + up to where the actual number starts)
    const dialCodeMatch = normalizedPhone.match(/^\+(\d{1,4})/);
    if (!dialCodeMatch) return null;

    const dialCode = `+${dialCodeMatch[1]}`;
    const country = COUNTRY_CODES.find(c => c.dial === dialCode);

    return country || null;
  };

  /**
   * Handle calls outside the dropdown to close it
   */
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (countryDropdownRef.current && !countryDropdownRef.current.contains(event.target)) {
        setShowCountryDropdown(false);
      }
    };

    const handleEscapeKey = (event) => {
      if (event.key === 'Escape' && showCountryDropdown) {
        setShowCountryDropdown(false);
      }
    };

    if (showCountryDropdown) {
      document.addEventListener('mousedown', handleClickOutside);
      document.addEventListener('keydown', handleEscapeKey);

      return () => {
        document.removeEventListener('mousedown', handleClickOutside);
        document.removeEventListener('keydown', handleEscapeKey);
      };
    }
  }, [showCountryDropdown]);

  /**
   * Get risk level from score
   */
  const getRiskLevel = (score) => {
    if (score >= 0.8) return { level: 'CRITICAL', color: t.riskHigh, emoji: '🔴' };
    if (score >= 0.6) return { level: 'HIGH', color: t.riskMed, emoji: '🟠' };
    if (score >= 0.4) return { level: 'MEDIUM', color: '#FFC107', emoji: '🟡' };
    if (score >= 0.2) return { level: 'LOW', color: t.riskLow, emoji: '🟢' };
    return { level: 'SAFE', color: '#4CAF50', emoji: '✅' };
  };

  /**
   * Filter countries based on search
   */
  const filteredCountries = COUNTRY_CODES.filter(c =>
    c.name.toLowerCase().includes(countrySearch.toLowerCase()) ||
    c.dial.includes(countrySearch)
  );

  /**
   * Handle phone number input
   */
  const handlePhoneChange = (e) => {
    const value = e.target.value;
    setPhoneInput(value);
    setError(null);

    // Try to detect country from input
    const normalized = normalizePhoneNumber(value);
    const detected = detectCountryFromPhone(normalized);
    setDetectedCountry(detected);
  };

  /**
   * Handle country selection from dropdown
   */
  const handleCountrySelect = (countryName) => {
    const countryObj = COUNTRY_CODES.find(c => c.name === countryName);
    if (countryObj) {
      setSelectedCountry(countryName);
      setCountrySearch(countryName);
    }
    setShowCountryDropdown(false);
  };

  /**
   * Clear country selection
   */
  const handleClearCountry = (e) => {
    e.stopPropagation();
    setSelectedCountry('');
    setCountrySearch('');
    setDetectedCountry(detectCountryFromPhone(normalizePhoneNumber(phoneInput)));
  };

  /**
   * Validate inputs before scan
   */
  const validateInputs = () => {
    if (!phoneNumber.trim()) {
      setError('Please enter a phone number');
      return false;
    }

    const cost = getCreditCost(scanMode);
    if (credits < cost) {
      setError(`Not enough credits for ${scanMode === 'deep' ? 'deep' : 'light'} scan. Required: ${cost}, Available: ${credits}`);
      return false;
    }

    return true;
  };

  /**
   * Perform phone lookup
   */
  const handleScan = async () => {
    if (!validateInputs()) return;

    setIsLoading(true);
    setError(null);
    setLookupResult(null);
    setProgress(0);

    try {
      // Simulate progress
      const progressInterval = setInterval(() => {
        setProgress((prev) => (prev < 90 ? prev + Math.random() * 20 : prev));
      }, 300);

      // Format phone number
      let fullPhone = phoneNumber.trim();

      // Only add dial code if a country is selected
      if (selectedDialCode && !fullPhone.startsWith('+')) {
        const local = fullPhone.replace(/^0+/, '');
        fullPhone = `${selectedDialCode}${local}`;
      }

      // Get ISO country code from selected country (optional)
      let countryCode = null;
      if (selectedCountry) {
        const countryObj = COUNTRY_CODES.find(c => c.name === selectedCountry);
        if (countryObj) {
          countryCode = countryObj.code;
        }
      }

      // Send request to backend with country and scan_type
      const response = await api.phoneLookup(fullPhone, countryCode, scanMode);

      clearInterval(progressInterval);
      setProgress(100);

      if (response.status === 'success' && response.data) {
        // Deduct credits
        const cost = getCreditCost(scanMode);
        setCredits(credits - cost);

        // Store result with metadata
        setLookupResult({
          ...response.data,
          scannedAt: new Date().toLocaleString(),
          scanMode,
          country: selectedCountry || response.data.country || 'Unknown'
        });
      } else {
        setError(response.message || 'Lookup failed');
      }
    } catch (err) {
      setError(`Error: ${err.message || 'Failed to perform scan'}`);
    } finally {
      setIsLoading(false);
      setTimeout(() => setProgress(0), 500);
    }
  };

  /**
   * Clear all inputs and results
   */
  const handleClear = () => {
    setPhoneNumber('');
    setSelectedCountry('');
    setCountrySearch('');
    setLookupResult(null);
    setError(null);
    setProgress(0);
  };

  /**
   * Export results
   */
  const handleExport = () => {
    if (!lookupResult) return;
    const data = JSON.stringify(lookupResult, null, 2);
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `phone-intel-${Date.now()}.json`;
    a.click();
  };

  return (
    <div className="phone-intel-container" style={{ color: t.text }}>
      {/* Header */}
      <div style={{
        marginBottom: 28,
        paddingBottom: 20,
        borderBottom: `1px solid ${t.border}`
      }}>
        <h2 style={{ 
          fontFamily: "'Sora',sans-serif", 
          fontWeight: 800, 
          fontSize: 24, 
          color: t.text, 
          margin: '0 0 8px 0' 
        }}>
          📱 Phone Intelligence Platform
        </h2>
        <p style={{ 
          fontFamily: "'Sora',sans-serif", 
          fontSize: 13, 
          color: t.textMuted, 
          margin: 0 
        }}>
          Advanced OSINT phone lookup with carrier detection, risk scoring, and social intelligence
        </p>
      </div>

      {/* Credits display */}
      <div style={{
        marginBottom: 20,
        padding: '12px 16px',
        background: t.surfaceAlt,
        border: `1px solid ${t.border}`,
        borderRadius: 8,
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center'
      }}>
        <span style={{ fontFamily: "'Sora',sans-serif", fontSize: 12, color: t.textMuted }}>
          💳 Available Credits
        </span>
        <span style={{ 
          fontFamily: "'JetBrains Mono',monospace", 
          fontSize: 16, 
          fontWeight: 700, 
          color: t.accent 
        }}>
          {credits}
        </span>
      </div>

      {/* Input Panel */}
      <div style={{
        background: t.surface,
        border: `1px solid ${t.border}`,
        borderRadius: 10,
        padding: 24,
        marginBottom: 24
      }}>
        <h3 style={{
          fontFamily: "'Sora',sans-serif",
          fontSize: 14,
          fontWeight: 700,
          color: t.text,
          margin: '0 0 18px 0',
          textTransform: 'uppercase',
          letterSpacing: 1,
          color: t.textSub
        }}>
          📡 Input Panel
        </h3>

        {/* Phone Number Input */}
        <div style={{ marginBottom: 18 }}>
          <label style={{
            display: 'block',
            fontFamily: "'JetBrains Mono',monospace",
            fontSize: 10,
            fontWeight: 700,
            color: t.textSub,
            marginBottom: 8,
            letterSpacing: 1.5,
            textTransform: 'uppercase'
          }}>
            Phone Number *
          </label>
          <input
            type="tel"
            value={phoneNumber}
            onChange={handlePhoneChange}
            placeholder="e.g., +233201234567 or 0201234567"
            disabled={isLoading}
            style={{
              width: '100%',
              padding: '12px 14px',
              background: t.inputBg,
              border: `1px solid ${t.border}`,
              borderRadius: 8,
              color: t.text,
              fontFamily: "'JetBrains Mono',monospace",
              fontSize: 14,
              outline: 'none',
              boxSizing: 'border-box',
              transition: 'all 0.2s',
              opacity: isLoading ? 0.6 : 1,
              cursor: isLoading ? 'not-allowed' : 'text'
            }}
            onFocus={(e) => {
              e.target.style.borderColor = t.accent;
              e.target.style.boxShadow = `0 0 0 3px ${t.accent}22`;
            }}
            onBlur={(e) => {
              e.target.style.borderColor = t.border;
              e.target.style.boxShadow = 'none';
            }}
          />
        </div>

        {/* Country Input with Dropdown */}
        <div style={{ marginBottom: 18, position: 'relative' }} ref={countryDropdownRef}>
          <label style={{
            display: 'block',
            fontFamily: "'JetBrains Mono',monospace",
            fontSize: 10,
            fontWeight: 700,
            color: t.textSub,
            marginBottom: 8,
            letterSpacing: 1.5,
            textTransform: 'uppercase'
          }}>
            Country (Optional - Click outside to close)
          </label>

          <div style={{ position: 'relative' }}>
            <input
              type="text"
              value={selectedCountry}
              onChange={(e) => {
                const val = e.target.value;
                setCountrySearch(val);
                if (selectedCountry) {
                  setSelectedCountry('');
                }
              }}
              onFocus={() => {
                setCountrySearch('');
                setShowCountryDropdown(true);
              }}
              placeholder="Select country code (optional)"
              disabled={isLoading}
              style={{
                width: '100%',
                padding: '12px 14px',
                paddingRight: selectedCountry ? '38px' : '14px',
                background: t.inputBg,
                border: `1px solid ${showCountryDropdown ? t.accent : t.border}`,
                borderRadius: showCountryDropdown ? '8px 8px 0 0' : 8,
                color: t.text,
                fontFamily: "'Sora',sans-serif",
                fontSize: 13,
                outline: 'none',
                boxSizing: 'border-box',
                transition: 'all 0.2s',
                opacity: isLoading ? 0.6 : 1,
                cursor: isLoading ? 'not-allowed' : 'text'
              }}
            />

            {/* Clear button */}
            {selectedCountry && (
              <button
                onClick={handleClearCountry}
                disabled={isLoading}
                style={{
                  position: 'absolute',
                  right: 10,
                  top: '50%',
                  transform: 'translateY(-50%)',
                  background: 'none',
                  border: 'none',
                  color: t.textMuted,
                  cursor: isLoading ? 'not-allowed' : 'pointer',
                  fontSize: 18,
                  padding: 0,
                  lineHeight: 1,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  opacity: isLoading ? 0.6 : 0.8,
                  transition: 'opacity 0.2s',
                  ':hover': {
                    opacity: 1,
                    color: t.accent
                  }
                }}
                onMouseEnter={(e) => {
                  e.target.style.opacity = '1';
                  e.target.style.color = t.accent;
                }}
                onMouseLeave={(e) => {
                  e.target.style.opacity = isLoading ? '0.6' : '0.8';
                  e.target.style.color = t.textMuted;
                }}
                title="Clear country selection"
              >
                ✕
              </button>
            )}

            {/* Country Dropdown */}
            {showCountryDropdown && (
              <div style={{
                position: 'absolute',
                top: '100%',
                left: 0,
                right: 0,
                maxHeight: 240,
                overflowY: 'auto',
                background: t.surface,
                border: `1px solid ${t.accent}66`,
                borderTop: 'none',
                borderRadius: '0 0 8px 8px',
                boxShadow: `0 8px 24px rgba(0,0,0,0.25)`,
                zIndex: 1000
              }}>
                {filteredCountries.length > 0 ? (
                  filteredCountries.map((country) => (
                    <div
                      key={country.code}
                      onClick={() => handleCountrySelect(country.name)}
                      style={{
                        padding: '10px 14px',
                        cursor: 'pointer',
                        borderBottom: `1px solid ${t.borderLight}`,
                        display: 'flex',
                        alignItems: 'center',
                        gap: 10,
                        transition: 'background 0.15s',
                        background: selectedCountry === country.name ? `${t.accent}22` : 'transparent'
                      }}
                      onMouseEnter={(e) => {
                        if (selectedCountry !== country.name) {
                          e.currentTarget.style.background = `${t.accent}0a`;
                        }
                      }}
                      onMouseLeave={(e) => {
                        e.currentTarget.style.background = selectedCountry === country.name ? `${t.accent}22` : 'transparent';
                      }}
                    >
                      <span style={{ fontSize: 18 }}>{country.flag}</span>
                      <span style={{ 
                        fontFamily: "'Sora',sans-serif", 
                        fontSize: 12, 
                        color: selectedCountry === country.name ? t.accent : t.text,
                        flex: 1
                      }}>
                        {country.name}
                      </span>
                      <span style={{ 
                        fontFamily: "'JetBrains Mono',monospace", 
                        fontSize: 11, 
                        color: t.textMuted,
                        fontWeight: 700
                      }}>
                        {country.dial}
                      </span>
                    </div>
                  ))
                ) : (
                  <div style={{
                    padding: '12px 14px',
                    textAlign: 'center',
                    fontFamily: "'Sora',sans-serif",
                    fontSize: 12,
                    color: t.textMuted
                  }}>
                    No countries found
                  </div>
                )}
              </div>
            )}
          </div>
        </div>

        {/* Scan Mode Selector */}
        <div style={{ marginBottom: 20 }}>
          <label style={{
            display: 'block',
            fontFamily: "'JetBrains Mono',monospace",
            fontSize: 10,
            fontWeight: 700,
            color: t.textSub,
            marginBottom: 10,
            letterSpacing: 1.5,
            textTransform: 'uppercase'
          }}>
            Scan Mode
          </label>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>
            {[
              { mode: 'light', label: '⚡ Light Scan', desc: 'Fast lookup', cost: 1 },
              { mode: 'deep', label: '🔍 Deep Scan', desc: 'Full OSINT', cost: 3 }
            ].map(({ mode, label, desc, cost }) => (
              <button
                key={mode}
                onClick={() => setScanMode(mode)}
                disabled={isLoading}
                style={{
                  padding: '12px 14px',
                  background: scanMode === mode ? `${t.accent}18` : t.inputBg,
                  border: `2px solid ${scanMode === mode ? t.accent : t.border}`,
                  borderRadius: 8,
                  color: scanMode === mode ? t.accent : t.text,
                  fontFamily: "'Sora',sans-serif",
                  fontSize: 12,
                  fontWeight: 700,
                  cursor: isLoading ? 'not-allowed' : 'pointer',
                  transition: 'all 0.2s',
                  opacity: isLoading ? 0.6 : 1,
                  display: 'flex',
                  flexDirection: 'column',
                  gap: 4
                }}
              >
                <span>{label}</span>
                <span style={{ 
                  fontSize: 10, 
                  color: t.textMuted, 
                  fontWeight: 500 
                }}>
                  {desc} • {cost} credit{cost > 1 ? 's' : ''}
                </span>
              </button>
            ))}
          </div>
        </div>

        {/* Action Buttons */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 10 }}>
          <button
            onClick={handleScan}
            disabled={isLoading || !phoneNumber.trim()}
            style={{
              padding: '12px 16px',
              background: isLoading ? t.border : t.accentGrad,
              color: '#fff',
              border: 'none',
              borderRadius: 8,
              fontFamily: "'Sora',sans-serif",
              fontSize: 13,
              fontWeight: 700,
              cursor: isLoading || !phoneNumber.trim() ? 'not-allowed' : 'pointer',
              opacity: isLoading || !phoneNumber.trim() ? 0.6 : 1,
              transition: 'all 0.2s',
              boxShadow: isLoading ? 'none' : `0 4px 12px ${t.accent}33`,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: 8
            }}
          >
            {isLoading ? (
              <>
                <span style={{ animation: 'spin 1s linear infinite' }}>⟳</span>
                Scanning...
              </>
            ) : (
              <>🔍 Start Scan</>
            )}
          </button>

          <button
            onClick={handleClear}
            disabled={isLoading}
            style={{
              padding: '12px 16px',
              background: t.inputBg,
              color: t.text,
              border: `1px solid ${t.border}`,
              borderRadius: 8,
              fontFamily: "'Sora',sans-serif",
              fontSize: 13,
              fontWeight: 700,
              cursor: isLoading ? 'not-allowed' : 'pointer',
              opacity: isLoading ? 0.6 : 1,
              transition: 'all 0.2s'
            }}
          >
            🔄 Clear
          </button>

          <button
            onClick={handleExport}
            disabled={isLoading || !lookupResult}
            style={{
              padding: '12px 16px',
              background: lookupResult ? t.accent : t.border,
              color: lookupResult ? '#fff' : t.textMuted,
              border: 'none',
              borderRadius: 8,
              fontFamily: "'Sora',sans-serif",
              fontSize: 13,
              fontWeight: 700,
              cursor: !lookupResult || isLoading ? 'not-allowed' : 'pointer',
              opacity: !lookupResult || isLoading ? 0.5 : 1,
              transition: 'all 0.2s'
            }}
          >
            💾 Export
          </button>
        </div>

        {/* Progress Bar */}
        {progress > 0 && progress < 100 && (
          <div style={{ marginTop: 16 }}>
            <div style={{
              height: 6,
              background: t.inputBg,
              borderRadius: 3,
              overflow: 'hidden'
            }}>
              <div style={{
                height: '100%',
                background: t.accentGrad,
                width: `${progress}%`,
                transition: 'width 0.3s ease'
              }} />
            </div>
            <div style={{
              marginTop: 8,
              fontFamily: "'JetBrains Mono',monospace",
              fontSize: 10,
              color: t.textMuted,
              textAlign: 'center'
            }}>
              {Math.round(progress)}% complete
            </div>
          </div>
        )}
      </div>

      {/* Error Message */}
      {error && (
        <div style={{
          marginBottom: 20,
          padding: '12px 14px',
          background: `${t.riskHigh}22`,
          border: `1px solid ${t.riskHigh}66`,
          borderRadius: 8,
          color: t.riskHigh,
          fontFamily: "'Sora',sans-serif",
          fontSize: 12,
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center'
        }}>
          <span>⚠️ {error}</span>
          <button
            onClick={() => setError(null)}
            style={{
              background: 'none',
              border: 'none',
              color: t.riskHigh,
              fontSize: 16,
              cursor: 'pointer',
              padding: 0
            }}
          >
            ×
          </button>
        </div>
      )}

      {/* Results Panel */}
      {lookupResult && (
        <div style={{ animation: 'fadeIn 0.4s ease' }}>
          <h3 style={{
            fontFamily: "'Sora',sans-serif",
            fontSize: 14,
            fontWeight: 700,
            color: t.text,
            margin: '0 0 16px 0',
            textTransform: 'uppercase',
            letterSpacing: 1,
            color: t.textSub
          }}>
            📊 Results Panel
          </h3>

          {/* Result Grid */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16, marginBottom: 20 }}>
            {/* Basic Info Card */}
            <div style={{
              background: t.surface,
              border: `1px solid ${t.border}`,
              borderRadius: 10,
              padding: 16,
              gridColumn: '1 / -1'
            }}>
              <h4 style={{
                fontFamily: "'Sora',sans-serif",
                fontSize: 12,
                fontWeight: 700,
                color: t.textSub,
                margin: '0 0 12px 0',
                textTransform: 'uppercase',
                letterSpacing: 1
              }}>
                Phone Details
              </h4>
              <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(3, 1fr)',
                gap: 12
              }}>
                <ResultItem label="Number" value={lookupResult.number || phoneNumber} theme={t} />
                <ResultItem label="Carrier" value={lookupResult.carrier || '—'} theme={t} />
                <ResultItem label="Country" value={lookupResult.country || selectedCountry || '—'} theme={t} />
                <ResultItem label="Region" value={lookupResult.region || '—'} theme={t} />
                <ResultItem label="Line Type" value={lookupResult.line_type || lookupResult.carrier_type || '—'} theme={t} />
                <ResultItem label="Valid" value={lookupResult.valid ? '✓ Yes' : '✗ No'} theme={t} />
              </div>
            </div>

            {/* Risk Score Card */}
            {lookupResult.risk_score !== undefined && (
              <div style={{
                background: t.surface,
                border: `1px solid ${t.border}`,
                borderRadius: 10,
                padding: 16
              }}>
                <h4 style={{
                  fontFamily: "'Sora',sans-serif",
                  fontSize: 12,
                  fontWeight: 700,
                  color: t.textSub,
                  margin: '0 0 12px 0',
                  textTransform: 'uppercase',
                  letterSpacing: 1
                }}>
                  Risk Score
                </h4>
                {(() => {
                  const riskInfo = getRiskLevel(lookupResult.risk_score);
                  return (
                    <div style={{ textAlign: 'center' }}>
                      <div style={{
                        width: 80,
                        height: 80,
                        borderRadius: '50%',
                        border: `4px solid ${riskInfo.color}`,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        margin: '0 auto 12px',
                        background: `${riskInfo.color}11`
                      }}>
                        <span style={{
                          fontSize: 32,
                          fontWeight: 700,
                          color: riskInfo.color
                        }}>
                          {Math.round(lookupResult.risk_score * 100)}
                        </span>
                      </div>
                      <div style={{
                        padding: '6px 10px',
                        background: riskInfo.color,
                        color: '#fff',
                        borderRadius: 6,
                        fontFamily: "'JetBrains Mono',monospace",
                        fontSize: 11,
                        fontWeight: 700,
                        display: 'inline-block',
                        marginBottom: 10
                      }}>
                        {riskInfo.emoji} {riskInfo.level}
                      </div>
                      <div style={{
                        fontFamily: "'Sora',sans-serif",
                        fontSize: 11,
                        color: t.textMuted
                      }}>
                        Confidence: {((lookupResult.confidence || 0) * 100).toFixed(0)}%
                      </div>
                    </div>
                  );
                })()}
              </div>
            )}

            {/* Spam Reports */}
            <div style={{
              background: t.surface,
              border: `1px solid ${t.border}`,
              borderRadius: 10,
              padding: 16
            }}>
              <h4 style={{
                fontFamily: "'Sora',sans-serif",
                fontSize: 12,
                fontWeight: 700,
                color: t.textSub,
                margin: '0 0 12px 0',
                textTransform: 'uppercase',
                letterSpacing: 1
              }}>
                Spam Reports
              </h4>
              <div style={{
                fontFamily: "'Sora',sans-serif",
                fontSize: 24,
                fontWeight: 700,
                color: t.text
              }}>
                {lookupResult.spam_reports || 0}
              </div>
              <div style={{
                fontFamily: "'Sora',sans-serif",
                fontSize: 11,
                color: t.textMuted,
                marginTop: 4
              }}>
                Reports found
              </div>
            </div>
          </div>

          {/* Linked Emails */}
          {(lookupResult.emails_found?.length > 0 || true) && (
            <div style={{
              background: t.surface,
              border: `1px solid ${t.border}`,
              borderRadius: 10,
              padding: 16,
              marginBottom: 16
            }}>
              <h4 style={{
                fontFamily: "'Sora',sans-serif",
                fontSize: 12,
                fontWeight: 700,
                color: t.textSub,
                margin: '0 0 12px 0',
                textTransform: 'uppercase',
                letterSpacing: 1
              }}>
                📧 Linked Emails
              </h4>
              {lookupResult.emails_found?.length > 0 ? (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                  {lookupResult.emails_found.map((email, idx) => (
                    <div key={idx} style={{
                      padding: '8px 12px',
                      background: t.inputBg,
                      border: `1px solid ${t.border}`,
                      borderRadius: 6,
                      fontFamily: "'JetBrains Mono',monospace",
                      fontSize: 11,
                      color: t.textMid
                    }}>
                      {email}
                    </div>
                  ))}
                </div>
              ) : (
                <div style={{
                  padding: '12px',
                  textAlign: 'center',
                  fontFamily: "'Sora',sans-serif",
                  fontSize: 12,
                  color: t.textMuted,
                  background: t.inputBg,
                  borderRadius: 6
                }}>
                  No emails found
                </div>
              )}
            </div>
          )}

          {/* Social Accounts */}
          {(lookupResult.social_accounts && Object.keys(lookupResult.social_accounts).length > 0 || true) && (
            <div style={{
              background: t.surface,
              border: `1px solid ${t.border}`,
              borderRadius: 10,
              padding: 16
            }}>
              <h4 style={{
                fontFamily: "'Sora',sans-serif",
                fontSize: 12,
                fontWeight: 700,
                color: t.textSub,
                margin: '0 0 12px 0',
                textTransform: 'uppercase',
                letterSpacing: 1
              }}>
                👥 Social Accounts
              </h4>
              {lookupResult.social_accounts && Object.keys(lookupResult.social_accounts).length > 0 ? (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                  {Object.entries(lookupResult.social_accounts).map(([platform, handle], idx) => (
                    <div key={idx} style={{
                      padding: '8px 12px',
                      background: t.inputBg,
                      border: `1px solid ${t.border}`,
                      borderRadius: 6,
                      display: 'flex',
                      justifyContent: 'space-between',
                      alignItems: 'center'
                    }}>
                      <span style={{
                        fontFamily: "'Sora',sans-serif",
                        fontSize: 11,
                        fontWeight: 600,
                        color: t.text
                      }}>
                        {platform.split('_').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ')}
                      </span>
                      <span style={{
                        fontFamily: "'JetBrains Mono',monospace",
                        fontSize: 10,
                        color: t.textMid
                      }}>
                        @{handle}
                      </span>
                    </div>
                  ))}
                </div>
              ) : (
                <div style={{
                  padding: '12px',
                  textAlign: 'center',
                  fontFamily: "'Sora',sans-serif",
                  fontSize: 12,
                  color: t.textMuted,
                  background: t.inputBg,
                  borderRadius: 6
                }}>
                  No social accounts found
                </div>
              )}
            </div>
          )}

          {/* Metadata */}
          <div style={{
            marginTop: 16,
            padding: '8px 12px',
            background: `${t.accent}11`,
            border: `1px dashed ${t.accent}44`,
            borderRadius: 6,
            fontFamily: "'JetBrains Mono',monospace",
            fontSize: 9,
            color: t.textMuted
          }}>
            Scanned: {lookupResult.scannedAt} • Mode: {lookupResult.scanMode?.toUpperCase()}
          </div>
        </div>
      )}

      {/* Empty State */}
      {!lookupResult && !isLoading && (
        <div style={{
          textAlign: 'center',
          padding: '60px 40px',
          background: t.surface,
          border: `1px dashed ${t.border}`,
          borderRadius: 10,
          color: t.textMuted
        }}>
          <div style={{ fontSize: 48, marginBottom: 16 }}>📱</div>
          <p style={{
            fontFamily: "'Sora',sans-serif",
            fontSize: 16,
            margin: '0 0 8px 0',
            color: t.text,
            fontWeight: 600
          }}>
            Enter a phone number to begin
          </p>
          <p style={{
            fontFamily: "'Sora',sans-serif",
            fontSize: 12,
            margin: 0,
            color: t.textMuted
          }}>
            Supports international formats with or without country codes
          </p>
        </div>
      )}

      <style>{`
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
        @keyframes fadeIn {
          from { opacity: 0; }
          to { opacity: 1; }
        }
      `}</style>
    </div>
  );
};

/**
 * Reusable result item component
 */
function ResultItem({ label, value, theme }) {
  const t = THEMES[theme.name ? theme : 'dark'];
  return (
    <div>
      <div style={{
        fontFamily: "'JetBrains Mono',monospace",
        fontSize: 9,
        color: t.textMuted,
        textTransform: 'uppercase',
        letterSpacing: 1,
        marginBottom: 4,
        fontWeight: 700
      }}>
        {label}
      </div>
      <div style={{
        fontFamily: "'Sora',sans-serif",
        fontSize: 13,
        color: t.text,
        fontWeight: 600,
        wordBreak: 'break-word'
      }}>
        {value}
      </div>
    </div>
  );
}

export default PhoneIntel;
